const Q_ECONOMICS_2008=[{"id": "objective>Economics>2008>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The production possibility curve can be used to explain the underlying concepts of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">scale of preference and choice </div>", "<div style=\"font-family:Cambria;font-size:17px;\">opportunity cost and choice </div>", "<div style=\"font-family:Cambria;font-size:17px;\">wants and means </div>", "<div style=\"font-family:Cambria;font-size:17px;\">opportunity cost and scale of preference</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A single production possibility curve illustrate three concepts which are: Choice, scarcity and opportunity cost. The concept of opportunity cost is used to explain the production possibility curve.</div>", "topic": "INTRODUCTION TO ECONOMICS : PRODUCTION POSSIBILITY CURVE"}, {"id": "objective>Economics>2008>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The deregulation of telecommunication services in Nigeria is a characteristic of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">command economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">traditional economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">market economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">feudal economy</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Deregulation is the removal of government control or imposed constraint or conditions in the economy.</div>", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM"}, {"id": "objective>Economics>2008>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the increase in the price of yams is used to estimate the inflation rate, this is an example of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">deductive reasoning</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inductive reasoning</div>", "<div style=\"font-family:Cambria;font-size:17px;\">normative reasoning</div>", "<div style=\"font-family:Cambria;font-size:17px;\">positive reasoning</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Inductive reasoning is an economic methodology that involves inference from a particular to general. Inductive reasoning is a type of logical reasoning that involves making generalizations based on specific observations. In this case, the observation is that the price of yams has increased. The generalization is that the overall inflation rate has increased.</div>", "topic": "INFLATION & DEFLATION : INTRODUCTION"}, {"id": "objective>Economics>2008>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the standard deviation of a given data is 8.2, find its variance. </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4.1 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">67.2 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">82.0 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">91.8 </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Standard deviation = √ variance  <br/> Square both side <br/>  Variance =SD<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>  <br/> V  = 8.2^2  <br/> = 67.2</div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF DISPERSION"}, {"id": "objective>Economics>2008>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><p style=\"padding: 3px;\">Use the data below to answer the question that follows</p> <br/>  <br/>  54, 36, 62, 79, 83, 36, 62, 42, 62 and 42. <br/>  <br/> Calculate the mean. </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">45.5  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">55.6 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">55.8  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">65.8</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">for ungrouped data <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\"><strong><em>X</em></strong></td><td style=\"text-align:center;\">(mean)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">∑X<hr size=\"1\" />n</td></tr></table></div>  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">54 + 36 + 62 + 79 + 83 + 36 + 62 + 42 + 62 + 42<hr size=\"1\" />10</td></tr></table></div>  <br/>  <br/>  = 558/10  <br/>  <br/> = 55.8</div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY"}, {"id": "objective>Economics>2008>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">Use the data below to answer the question that follows</p> <br/>  <br/>  54, 36, 62, 79, 83, 36, 62, 42, 62 and 42. <br/> What is the modal score? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">36 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">42 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">54 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">62 </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Modal score is the observation with the highest frequency or occurrence . Therefore,mode is 62 because it appears three times.</div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY"}, {"id": "objective>Economics>2008>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major determinant of the demand for a luxury good is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the price of the good </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the price of other goods </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the income of consumers </div>", "<div style=\"font-family:Cambria;font-size:17px;\">tastes and fashion</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">For a luxury goods, income will be an important determinant of demand. e.g. if your income increased you would buy more restaurant meals and vice versa. Income and luxury goods have a direct relationship.</div>", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>2008>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If 100 units and 120 units of commodity X are supplied at ₦80 at different times, it means that there is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a change in supply </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a change in the quantity supplied </div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in the quantity supplied </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in the quantity  supplied</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A shift or change in supply curve occurs when there is change in the quantity while the price remains constant. A change or shift in supply is determined by the factors affecting supply except the price of the commodity.</div>", "topic": "THEORY OF SUPPLY : DISTINCTION BETWEEN CHANGE IN QUANTITY SUPPLIED AND CHANGE IN SUPPLY"}, {"id": "objective>Economics>2008>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If income rises from ₦2000 to ₦4000 and quantity demanded increases from 80 units to 120 units, find the income elasticity of demand. </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.0</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Using ey = ∆QD/∆Y  x  Y  /QD <br/> where ∆QD = Q2 - Q1 <br/>            ∆Y = Y2 - Y1 <br/>             QD = Original quantity( 1st quantity) <br/>              Y = Original income ( 1st income) <br/>  <br/> Therefore, Ey = 120 -80 / 4000 - 2000  x 2000/80 <br/>                                 = 40/2000  x 2000/80 <br/>                                            = 0.5 <br/>                           <br/> ALTERNATIVELY: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Ey</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">% Δ in Qd<hr size=\"1\" />% Δ in Y</td></tr></table></div>  <br/>    <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">% Δ in Y</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4000 - 2000<hr size=\"1\" />2000</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100<hr size=\"1\" />1</td></tr></table></div>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2000<hr size=\"1\" />2000</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">100</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">100%</td></tr></table></div>  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">% Δ in Qd</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">120 - 80<hr size=\"1\" />80</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100</td></tr></table></div>  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">40<hr size=\"1\" />80</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100<hr size=\"1\" />1</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">50%</td></tr></table></div>  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Y<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">ED</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">50<hr size=\"1\" />100</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">or</td><td style=\"text-align:center;\">0.5</td></tr></table></div></div>", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND"}, {"id": "objective>Economics>2008>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the demand elasticity coefficient of cars is 0.5, it implies that the demand for petrol is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">elastic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">perfectly inelastic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inelastic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">perfectly elastic.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cars and petrol are jointly demanded to satisfy a particular want.Therefore, the demand for petrol will be inelastic since car is also inelastic.</div>", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND"}, {"id": "objective>Economics>2008>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">As long as marginal utility is positive, total utility must be </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">negative </div>", "<div style=\"font-family:Cambria;font-size:17px;\">increasing </div>", "<div style=\"font-family:Cambria;font-size:17px;\">zero </div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreasing</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The relationship between MU and TU are as follows: <br/> - When TU is rising , MU is positive <br/> - When TU is at the maximum point, MU is zero <br/> - When TU is falling, MU is negative</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : DIMINISHING MARGINAL UTILITY AND LAW OF DEMAND"}, {"id": "objective>Economics>2008>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Diminishing marginal utility implies that </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">total utility decreases as consumption increases. </div>", "<div style=\"font-family:Cambria;font-size:17px;\">marginal utility increases as consumption increases </div>", "<div style=\"font-family:Cambria;font-size:17px;\">marginal utility decreases as consumption increases </div>", "<div style=\"font-family:Cambria;font-size:17px;\">marginal utility decreases as consumption decreases.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The law of diminishing marginal utility states that the amount of satisfaction derived from the consumption of successive units of the same commodity will decline. The law is used to explain the downward-sloping nature of the normal demand curve.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : DIMINISHING MARGINAL UTILITY AND LAW OF DEMAND"}, {"id": "objective>Economics>2008>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The excess benefit derived from the purchase of goods over the amount paid for them is referred to as consumer </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rationality </div>", "<div style=\"font-family:Cambria;font-size:17px;\">surplus </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sovereignty </div>", "<div style=\"font-family:Cambria;font-size:17px;\">credit</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Consumer surplus is the difference between how much a consumer is willing to pay for a good and how much he eventually pays.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONSUMER SURPLUS"}, {"id": "objective>Economics>2008>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An upward movement along the same supply curve results in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an increase in supply </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in price </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in quantity supplied </div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in quantity supplied.   </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An upward movement along the supply curve indicates an increase in quantity supplied of a commodity due to a rise in its price, while a downward movement means a decrease in quantity supplied due to a fall in prices.</div>", "topic": "THEORY OF SUPPLY : DISTINCTION BETWEEN CHANGE IN QUANTITY SUPPLIED AND CHANGE IN SUPPLY"}, {"id": "objective>Economics>2008>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><p style=\"padding: 3px;\">Use the information below to answer the question that follows</p> <br/>  <br/>  <br/>  Given that Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">d</span>= 20 – 4P and Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span> = 6P + 12 <br/>  <br/> Determine the equilibrium quantity. </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">14.2 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">16.8 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">20.8 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">30.2</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> Firstly determine the Equilibrium price i.e  Qd = Qs  <br/>  20 - 4p = 6p + 12  <br/>  20 - 12 = 6P + 4P  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">8<hr size=\"1\" />10</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">10P<hr size=\"1\" />10</td></tr></table></div>  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">8<hr size=\"1\" />10</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4<hr size=\"1\" />5</td></tr></table></div>  <br/>  Qd = 20 - 4(4/5)  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">20<hr size=\"1\" />1</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">16<hr size=\"1\" />15</td></tr></table></div>  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">100 - 16<hr size=\"1\" />15</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">84<hr size=\"1\" />5</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">16.8</td></tr></table></div></div>", "topic": "THE THEORY OF PRICE DETERMINATION : DETERMINANTS OF PRICE UNDER FREE MARKET"}, {"id": "objective>Economics>2008>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">Use the information below to answer the question that follows</p> <br/>  <br/>  <br/>  Given that Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">d</span>= 20 – 4P and Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span> = 6P + 12 <br/> If price is increased to ₦3, how much is the excess supply? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">30</div>", "<div style=\"font-family:Cambria;font-size:17px;\">22</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Now price = ₦3 sub the value into the demand and supply function <br/>  <br/>  Qs= 6(3) + 12  <br/>  = 18 + 12 <br/>  = 30 <br/>  <br/> Qd=20-4(3) <br/>      =20-12 <br/>             =8 <br/>  <br/> excess supply= Qs-Qd <br/>                        =30-8 <br/>                         =22units</div>", "topic": "THE THEORY OF PRICE DETERMINATION : DETERMINANTS OF PRICE UNDER FREE MARKET"}, {"id": "objective>Economics>2008>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the factors affecting the supply of manufactured goods is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">weather </div>", "<div style=\"font-family:Cambria;font-size:17px;\">technology </div>", "<div style=\"font-family:Cambria;font-size:17px;\">consumer tastes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">availability of inputs</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Technology to a very extent influence supply. It is the availability of technology that will determine the method of production (i.e., either labour or capital intensive) as well as the processing and storage facilities.</div>", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>2008>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Individual markets differ from each other according to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the degree of competition </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the volume of trade </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the number of buyers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">its composition</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Market situations differ from one another primarily on the basis of the extent to which individual buyers and sellers can, by indepen­dent action, influence price. Market structure is the nature and degree of competition in the market for goods and services.</div>", "topic": "MARKET STRUCTURE : MEANING OF MARKET & TYPES"}, {"id": "objective>Economics>2008>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  <br/> In the diagram above, there is an excess</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">demand of 30 units </div>", "<div style=\"font-family:Cambria;font-size:17px;\">supply of 40 units </div>", "<div style=\"font-family:Cambria;font-size:17px;\">demand for 20 units </div>", "<div style=\"font-family:Cambria;font-size:17px;\">supply of 20 units. </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">From the graph above, demand fals to 20 unit while supply increase to 40 unit. <br/> Therefore, there is an Excess supply of 20 units i.e  40 - 20  <br/> = 20 units </div>", "topic": "THE THEORY OF PRICE DETERMINATION : EFFECT OF CHANGE IN SUPPLY & DEMAND ON EQUILIBRIUM PRICE & QUANTITY"}, {"id": "objective>Economics>2008>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">To protect farmers during a bumper harvest, the government usually </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">set a maximum price </div>", "<div style=\"font-family:Cambria;font-size:17px;\">release products from the buffer stock </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sell the excess to consumers </div>", "<div style=\"font-family:Cambria;font-size:17px;\">set a minimum price</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To protect farmers during a bumper harvest, the government usually sets a minimum price. This is known as price floor. A price floor is a government- or group-imposed price control or limit on how low a price can be charged for a product. A price floor must be higher than the equilibrium price in order to be effective. The government sets a minimum price to prevent prices from being too low, thus ensuring farmers can still make a profit even when there is a surplus of goods.</div>", "topic": "AGRICULTURE IN WEST AFRICA : MARKETING BOARDS"}, {"id": "objective>Economics>2008>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The use of modern weaving machines in the production of local fabric will result in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an increase in the demand for labour </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in the demand for labour </div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in wages </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in wages</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In production process, two methods are adopted i.e., it's either labour or capital intensive. Labour intensive method of production involves the use of more people and less machine for production processes which subsequently increase the demand for labour. Capital intensive method of production involves the use of less people and more machine for production processes which subsequently decrease the demand for labour.</div>", "topic": "THEORY OF PRODUCTION (1) : DIVISION OF LABOUR & SPECIALISATION"}, {"id": "objective>Economics>2008>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a perfectly competitive condition, a firm uses 10 units of labour at ₦25 and 11 units at ₦36, what is the marginal cost of labour? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦396 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦323 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦250 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦146 </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Marginal cost is the additional cost a firm incurs as a result of the production of a unit more of a production.  <br/> Therefore,  <br/> TC=10 x25=250 <br/> TC=11 x 36=396 <br/>  <br/> MC=∆TC/∆Q  <br/>       =396-250/11-10 <br/> MC=146.</div>", "topic": "THEORY OF PRODUCTION (2) : PRODUCERS EQUILIBRIUM"}, {"id": "objective>Economics>2008>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  <br/> From the graph above, point M shows that MC </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cuts AC at its minimum point </div>", "<div style=\"font-family:Cambria;font-size:17px;\">and AC rise simultaneously </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cuts AC at its maximum point </div>", "<div style=\"font-family:Cambria;font-size:17px;\">is falling</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Marginal cost rises while Average cost decreases and vice-versa.marginal cost cut the average cost below at is lowest or minimum points.</div>", "topic": "THE CONCEPT OF COST & REVENUE : THE MARGINAL COST & SUPPLY CURVE OF A FIRM"}, {"id": "objective>Economics>2008>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The characteristics of entry and exit ensures that firms </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">earn excess profit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">earn normal profit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">break-even</div>", "<div style=\"font-family:Cambria;font-size:17px;\">expand their operation.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The first of the folds is entry and exit of firms into and out of the industry. This ensures that firms earn zero economic profit and that price is equal to average cost. The second of the folds is the pursuit of profit maximization by each firm in the industry.</div>", "topic": "MARKET STRUCTURE : PERFECT MARKET"}, {"id": "objective>Economics>2008>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following producers is closest to being a monopolist?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">A baker </div>", "<div style=\"font-family:Cambria;font-size:17px;\">A wheat farmer </div>", "<div style=\"font-family:Cambria;font-size:17px;\">A large chain store </div>", "<div style=\"font-family:Cambria;font-size:17px;\">An automobile plant.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A monopolist is a single seller in a market with high barriers to entry. An automobile plant is closest to being a monopolist because it requires a large capital investment to start and operate, creating a high barrier to entry. The other options like a baker, a wheat farmer, or a large chain store operate in markets with many sellers and relatively low barriers to entry.</div>", "topic": "MARKET STRUCTURE : IMPERFECT MARKET ( MONOPOLY)"}, {"id": "objective>Economics>2008>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The output approach to measuring national income is based on the computation of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">final output</div>", "<div style=\"font-family:Cambria;font-size:17px;\">factor cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">value added</div>", "<div style=\"font-family:Cambria;font-size:17px;\">profit earned</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The output approach to measuring national income is based on the computation of the value added on the input, for example, flour is turned to bread or cake as a result of the value added to the flour.</div>", "topic": "NATIONAL INCOME : MEASUREMENT OF NATIONAL INCOME"}, {"id": "objective>Economics>2008>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of injection into the circular flow of income is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">taxes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">pensions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">imports</div>", "<div style=\"font-family:Cambria;font-size:17px;\">exports</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An injection in the circular flow of income is export.it increases the income level.injection are the economic variable that increases national income such as export,investment,tax e.t.c</div>", "topic": "EQUILIBRIUM LEVEL OF NATIONAL INCOME : INTRODUCTION"}, {"id": "objective>Economics>2008>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The theoretical relationship between money supply and prices is weakened by changes in the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">money supply </div>", "<div style=\"font-family:Cambria;font-size:17px;\">general price level</div>", "<div style=\"font-family:Cambria;font-size:17px;\">velocity of money</div>", "<div style=\"font-family:Cambria;font-size:17px;\">interest rate</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The theoretical relationship between money supply and prices is often described by the Quantity Theory of Money, which states that the general price level of goods and services is directly proportional to the amount of money in circulation, or money supply. However, this relationship is weakened by changes in the 'velocity of money'. The velocity of money refers to the frequency at which one unit of currency is used to purchase domestically- produced goods and services within a given time period. It is the rate at which money is exchanged from one transaction to another. If the velocity of money changes, it can disrupt the direct relationship between money supply and prices.</div>", "topic": "MONEY : SUPPLY OF MONEY"}, {"id": "objective>Economics>2008>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The high rate of inflation in Nigeria can be attributed to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increasing cost of production </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the appreciation of the naira </div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreasing cost of production </div>", "<div style=\"font-family:Cambria;font-size:17px;\">high capacity utilization.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Inflation occurs as a result of persistent rise in the general price level which can occur as a result of excess demand over supply or an increase in the cost of production.</div>", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL"}, {"id": "objective>Economics>2008>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the required reserves of a bank is 20% and ₦10,000 is paid into its demand deposit account, what is the excess reserves?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦2000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦8000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦12000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦18000</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The excess reserves is calculated by subtracting the required reserves from the total deposit. In this case, the required reserves is 20% of ₦10,000, which is ₦2000. Therefore, the excess reserves is ₦10,000 - ₦2000 = ₦8000.</div>", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS"}, {"id": "objective>Economics>2008>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Contractionary monetary policy is used to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">control inflation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">bridge the deflationary gap </div>", "<div style=\"font-family:Cambria;font-size:17px;\">expand the output level</div>", "<div style=\"font-family:Cambria;font-size:17px;\">deregulate the economy.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Contradictory monetary policy, also known as contractionary monetary policy, is a type of economic policy that involves reducing the amount of money in circulation in order to control inflation.</div>", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL"}, {"id": "objective>Economics>2008>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The use of government revenue and expenditure to achieve set objectives is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">budget</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fiscal policy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">revenue allocation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">monetary policy</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fiscal policy is a deliberate process by which government uses taxes and government expenditure to control and regulate inflation or the economy.</div>", "topic": "PUBLIC FINANCE : FISCAL POLICY"}, {"id": "objective>Economics>2008>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of indirect tax is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">profit tax</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sales tax</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital tax</div>", "<div style=\"font-family:Cambria;font-size:17px;\">poll tax</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Example of indirect tax are: Custom duties or Tarrifs, Export duties, Excise duties, Value-added tax, Sales tax, Purchase tax.</div>", "topic": "PUBLIC FINANCE : CLASSIFICATION OF TAX"}, {"id": "objective>Economics>2008>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A good indicator of economic development is an increase in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">gross national product </div>", "<div style=\"font-family:Cambria;font-size:17px;\">per capita income </div>", "<div style=\"font-family:Cambria;font-size:17px;\">real national income </div>", "<div style=\"font-family:Cambria;font-size:17px;\">real per capita income</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Economic development is a multi-dimensional and structural growth in the economy such that it improves the welfare and standard of living of people.</div>", "topic": "ECONOMIC DEVELOPMENT : INDICATORS OF GROWTH & DEVELOPMENT"}, {"id": "objective>Economics>2008>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Economic growth takes place when there is an increase in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">savings over time </div>", "<div style=\"font-family:Cambria;font-size:17px;\">investment over time </div>", "<div style=\"font-family:Cambria;font-size:17px;\">population over time </div>", "<div style=\"font-family:Cambria;font-size:17px;\">output over time</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Economic growth takes place when there is an increase in output over time. Economic growth is measured by the increase in a country's total output or production of goods and services. While savings, investment, and population can contribute to economic growth, they are not measures of growth themselves. Therefore, an increase in output over time is the correct answer.</div>", "topic": "ECONOMIC DEVELOPMENT : INDICATORS OF GROWTH & DEVELOPMENT"}, {"id": "objective>Economics>2008>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the effects of instability in farmers' income in Nigeria is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lack of infrastructure facilities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rural-urban migration </div>", "<div style=\"font-family:Cambria;font-size:17px;\">inadequate supply of fertilizer </div>", "<div style=\"font-family:Cambria;font-size:17px;\">low level of technology</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Instability in farmers' income in Nigeria can lead to rural-urban migration. This is because when farmers' income is unstable, they may not be able to sustain their livelihoods in rural areas, leading them to migrate to urban areas in search of better economic opportunities.</div>", "topic": "AGRICULTURE IN WEST AFRICA : FEATURES"}, {"id": "objective>Economics>2008>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major impediment to the development of agriculture in Nigeria is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">land use system </div>", "<div style=\"font-family:Cambria;font-size:17px;\">inadequate supply of farm  inputs </div>", "<div style=\"font-family:Cambria;font-size:17px;\">low income of farmers </div>", "<div style=\"font-family:Cambria;font-size:17px;\">limited research on seedlings.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Farm inputs are the resources that are used in farm production, such as chemicals, equipment, feed, seed, and energy.  One of the problems faced by the agricultural sector is the lack of these farm inputs that fast track crop production.</div>", "topic": "AGRICULTURE IN WEST AFRICA : FEATURES"}, {"id": "objective>Economics>2008>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major consideration in locating a cement factory is the availability of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">skilled labour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">power</div>", "<div style=\"font-family:Cambria;font-size:17px;\">infrastructure facilities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">limestone</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The most important \"location factor\" for cement industry is related to availability of raw-material and distance between raw-material source and the factory regard to the efficiency of transportation cost.  Limestone is an essential raw material in the production of cement.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION"}, {"id": "objective>Economics>2008>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The export-promotion strategy is aimed at producing </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">consumer goods originally  imported </div>", "<div style=\"font-family:Cambria;font-size:17px;\">machinery for industries </div>", "<div style=\"font-family:Cambria;font-size:17px;\">more goods for exports </div>", "<div style=\"font-family:Cambria;font-size:17px;\">more goods for domestic  consumption.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The export-promotion strategy is aimed at producing more goods for exports. This strategy is used by countries to increase their foreign exchange earnings, improve their balance of payments, and accelerate their rate of economic growth. It involves producing goods not for domestic consumption but for exports to other countries.</div>", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE"}, {"id": "objective>Economics>2008>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The activities in the oil and gas industry are classified into </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">exploration and transportation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">upstream and downstream</div>", "<div style=\"font-family:Cambria;font-size:17px;\">discovery and extraction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">onshore and offshore</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Upstream activities in the oil and gas industry involve all the exploration processes involved in the oil and gas industry while the Downstream-activities involve all the processing.</div>", "topic": "PETROLEUM AND THE NIGERIA ECONOMY : ONSHORE & OFFSHORE OF THE OIL SECTOR"}, {"id": "objective>Economics>2008>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The economic policy of privatization came up as a result of the poor performance of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">commercial banks</div>", "<div style=\"font-family:Cambria;font-size:17px;\">small-scale businesses</div>", "<div style=\"font-family:Cambria;font-size:17px;\">public enterprises</div>", "<div style=\"font-family:Cambria;font-size:17px;\">private enterprises</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Privatization is a deliberate process or policy in which publicly owned companies are being controlled and managed by individuals or group of individuals.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : COMMERCIALISATION & PRIVATISATION"}, {"id": "objective>Economics>2008>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Joint-stock companies can raise funds from </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the money market</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the capital market</div>", "<div style=\"font-family:Cambria;font-size:17px;\">various sources</div>", "<div style=\"font-family:Cambria;font-size:17px;\">government</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Joint-stock companies can raise funds from various sources. These sources include issuing shares, debentures, bonds, loans from financial institutions, retained earnings, etc. The money market and the capital market are part of these various sources, but not the only ones. The money market is a sector of the financial market in which financial instruments with high liquidity and short maturities are traded. The capital market is a financial market in which long-term debt or equity-backed securities are bought and sold.</div>", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES"}, {"id": "objective>Economics>2008>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The active population of a country determines the size of its</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">economic resources</div>", "<div style=\"font-family:Cambria;font-size:17px;\">national income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">labour force </div>", "<div style=\"font-family:Cambria;font-size:17px;\">gross domestic product</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The active population of a country determines the size of its labour force. The active population refers to the part of the population that is of working age and is either employed or actively looking for employment. This does not directly determine the size of economic resources, national income, or gross domestic product, although it can influence them.</div>", "topic": "POPULATION : DETERMINANTS OF POPULATION SIZE"}, {"id": "objective>Economics>2008>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  <br/> From the shaded area of the diagram above, an appropriate population policy will be to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">encourage early marriages </div>", "<div style=\"font-family:Cambria;font-size:17px;\">discourage immigration </div>", "<div style=\"font-family:Cambria;font-size:17px;\">discourage polygamy </div>", "<div style=\"font-family:Cambria;font-size:17px;\">encourage the use of contraceptive</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The shaded portion illustrates a situation of under-population. Hence, to raise the population, the government will encourage early marriage.</div>", "topic": "POPULATION : POPULATION STRUCTURE/ DISTRIBUTION"}, {"id": "objective>Economics>2008>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The population of a country will decrease if </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the death rate exceeds the birth rate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">immigration is equal to emigration </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the birth rate exceeds the death rate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">there is rapid economic growth</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Death decreases population while birth increases it. In a situation whereby death rate exceeds birth rate, the logical conclusion will be that it leads to decreasing population.</div>", "topic": "POPULATION : OVER POPULATION, UNDER POPULATION"}, {"id": "objective>Economics>2008>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The OPEC marketing policy of fixing minimum price allows members to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sell above minimum price </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sell below minimum price </div>", "<div style=\"font-family:Cambria;font-size:17px;\">determine the price and quantity  to sell </div>", "<div style=\"font-family:Cambria;font-size:17px;\">negotiate price with customers.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A policy of fixing minimum price implies that a commodity can be sold above an equilibrium price but cannot be sold below it.</div>", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : OPEC, ECA, IMF"}, {"id": "objective>Economics>2008>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major trading problem facing ECOWAS is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the absence of common currency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">political instability</div>", "<div style=\"font-family:Cambria;font-size:17px;\">high poverty level </div>", "<div style=\"font-family:Cambria;font-size:17px;\">non-implementation of decisions</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Economic Community of West African States (ECOWAS) is a regional group of fifteen West African countries. One of the major trading problems facing ECOWAS is the non-implementation of decisions. This is because, despite the various protocols and treaties that have been signed to facilitate trade among member countries, many of these agreements are not fully implemented. This hampers the free movement of goods and services, thereby affecting trade within the region.</div>", "topic": "INTERNATIONAL TRADE : ECONOMIC INTEGRATION IN AFRICA"}, {"id": "objective>Economics>2008>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A high rent on land will affect the cost of producing maize</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">positively</div>", "<div style=\"font-family:Cambria;font-size:17px;\">negatively </div>", "<div style=\"font-family:Cambria;font-size:17px;\">at the early stage of production </div>", "<div style=\"font-family:Cambria;font-size:17px;\">at the later stage of production</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The cost of producing maize or any other crop is directly affected by the cost of land. If the rent on land is high, it increases the cost of production. This is because the rent on land is part of the production cost. Therefore, a high rent on land will negatively affect the cost of producing maize as it will increase the cost of production.</div>", "topic": "FACTORS OF PRODUCTION & THEIR THEORIES : RENT & INTEREST"}, {"id": "objective>Economics>2008>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the active population is 50 million and unemployed is 5 million, what is the unemployment rate? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">10%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">45%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">55%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">90%</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Unemployment</td><td style=\"text-align:center;\">rate</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">No of Unemployed<hr size=\"1\" />Labour force</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100<hr size=\"1\" />1</td></tr></table></div> <br/>  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">5,000,000<hr size=\"1\" />50,000,000</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100<hr size=\"1\" />1</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">10%</td></tr></table></div></div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT : THE CONCEPT OF UNEMPLOYMENT"}, {"id": "objective>Economics>2008>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A classroom teacher is promoted to the rank of a principal. This is an example of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">vertical mobility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lateral mobility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">social mobility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">horizontal mobility</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Labour mobility is the movement of labour along the social ladder. Hence, an upward movement in the social ladder implies a vertical movement.</div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT : INTRODUCTION"}];
